record.field:
# Auto process attachments tagged 'Invoice' not linked yet
attachments = env['ir.attachment'].sudo().search([
    ('res_model','=',False),
    ('type','=','binary'),
    ('mimetype','!=',False),
], limit=10)
for a in attachments:
    try:
        env['psm.ai.invoice.service'].process_attachment(a)
    except Exception as e:
        # Log error to server logs / mail.message to keep trace
        _logger = logging.getLogger('psm_ai_invoice.cron')
        _logger.exception('AI invoice cron error for attachment %s: %s', a.id, e)
